import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  DateRangeFilter,
  LinListTableConfigModal,
  Select,
  dispatchAppToast,
  LinPageLayout,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useCatalogTableBusy,
  type DateRangeValue,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionStageDto, StageTrackingDto } from '../../../services/sx/models';
import { dinhMucKhoanPageLabels as labels } from '../../../constants/dinhMucKhoanPageLabels';
import { formatDateLocal, formatNumber } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useMesDinhMucKhoanPermissions } from '../../../hooks/useMesPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-dinh-muc-khoan';
const PAGE_ID = 'sx-dinh-muc-khoan';

const TRACKING_STATUS: Record<string, string> = {
  Pending: labels.statusPending,
  QcApproved: labels.statusApproved,
  QcRejected: labels.statusRejected,
};

function monthRange() {
  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const to = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);
  return { from, to };
}

const DinhMucKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useMesDinhMucKhoanPermissions();
  const defaultRange = monthRange();
  const [fromDate, setFromDate] = useState(defaultRange.from);
  const [toDate, setToDate] = useState(defaultRange.to);
  const [stageId, setStageId] = useState('');
  const [stages, setStages] = useState<ProductionStageDto[]>([]);
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [configOpen, setConfigOpen] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(`${TEST_ID}-report-table-config`),
  );

  const { showTableLoading } = useCatalogTableBusy(loading);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      sxService
        .getStages()
        .then(s => {
          if (!cancelled) setStages(s);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.stagesLoadError),
              type: 'error',
            });
          }
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch]);

  const handleLoad = useCallback(() => {
    setLoading(true);
    sxService
      .getStageTracking({
        stageId: stageId || undefined,
        fromDate,
        toDate,
        page: 1,
        pageSize: 200,
      })
      .then(res => {
        setRows(res.items);
        setLoaded(true);
      })
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dispatch, fromDate, toDate, stageId]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const totalOut = rows.reduce((a, r) => a + r.outQty, 0);
  const totalDefect = rows.reduce((a, r) => a + r.defectQty, 0);

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(`${TEST_ID}-report-table-config`, next);
  };

  const stageOptions = useMemo(
    () => [
      { value: '', label: labels.stageAll },
      ...stages.map(s => ({ value: s.id, label: `${s.code} — ${s.name}` })),
    ],
    [stages],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <div className={erp.field}>
            <DateRangeFilter
              label={labels.dateLabel}
              fullWidth
              testId={`${TEST_ID}-date-range`}
              fromDate={fromDate}
              toDate={toDate}
              onChange={(v: DateRangeValue) => {
                setFromDate(v.fromDate ?? '');
                setToDate(v.toDate ?? '');
              }}
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-stage`,
        content: (
          <div className={erp.field}>
            <Select
              label={labels.stageLabel}
              value={stageId}
              onChange={e => setStageId(e.target.value)}
              options={stageOptions}
              size="small"
            />
          </div>
        ),
      },
      ...(perms.canRead
        ? [
            {
              testId: `${TEST_ID}-view-btn`,
              content: (
                <Button
                  variant="primary"
                  onClick={handleLoad}
                  loading={loading}
                  data-testid={`${TEST_ID}-view-btn`}
                >
                  {labels.view}
                </Button>
              ),
            },
          ]
        : []),
    ],
    [fromDate, toDate, stageId, stageOptions, handleLoad, loading, perms.canRead],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: () => {
        if (perms.canRead) handleLoad();
      },
      canPrint: perms.canRead && loaded && rows.length > 0,
      onPrint: () => window.print(),
      onEditConfig: perms.canConfig ? () => setConfigOpen(true) : undefined,
    }),
    [handleLoad, loaded, rows.length, perms],
  );

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colDate}</th>
              <th>{labels.colLsx}</th>
              <th>{labels.colStage}</th>
              <th className={erp.colRight}>{labels.colInQty}</th>
              <th className={erp.colRight}>{labels.colOutQty}</th>
              <th className={erp.colRight}>{labels.colDefectQty}</th>
              <th>{labels.colStatus}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                <td>{formatDateLocal(r.trackingDate)}</td>
                <td>
                  <code>{r.productionOrderCode}</code>
                </td>
                <td>{r.stageName}</td>
                <td className={erp.colRight}>{formatNumber(r.inQty)}</td>
                <td className={erp.colRight}>{formatNumber(r.outQty)}</td>
                <td className={erp.colRight}>{formatNumber(r.defectQty)}</td>
                <td>
                  <span className={erp.tagDefault}>
                    {TRACKING_STATUS[r.status] ?? r.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          subTitle: labels.subtitle,
          titleIconClass: 'fas fa-chart-bar',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          loaded && rows.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.summaryItem}>
                {labels.summaryOut}: <strong>{formatNumber(totalOut)}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryDefect}: <strong>{formatNumber(totalDefect)}</strong>
              </span>
              <span className={erp.totalCount}>
                {labels.summaryRows}: {rows.length}
              </span>
            </div>
          ) : undefined
        }
        modals={
          <LinListTableConfigModal
            isOpen={configOpen}
            onClose={() => setConfigOpen(false)}
            testIdPrefix={TEST_ID}
            config={tableConfig}
            onSave={handleSaveTableConfig}
          />
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default DinhMucKhoanPage;
